export function resolveAllowedOrigin(origin: string | undefined): string | null {
  if (!origin) return null;
  for (const pattern of _allowedOriginPatterns) {
    if (pattern === origin) return origin;
    const wildcardIndex = pattern.indexOf("*");
    if (wildcardIndex >= 0) {
      const prefix = pattern.slice(0, wildcardIndex);
      const suffix = pattern.slice(wildcardIndex + 1);
      if (
        origin.length >= prefix.length + suffix.length &&
        origin.startsWith(prefix) &&
        origin.endsWith(suffix)
      ) {
        return origin;
      }
    }
  }
  return null;
}

const _baseHeaders = {
  "content-type": "application/json; charset=utf-8"
};

export function resolveCorsHeaders(req: IncomingMessage): Record<string, string> {
  const headers: Record<string, string> = { vary: "origin" };
  const origin = req?.headers?.origin;
  const echoOrigin = resolveAllowedOrigin(origin);
  if (echoOrigin) {
    headers["access-control-allow-origin"] = echoOrigin;
    headers["access-control-allow-credentials"] = "true";
  }
  return headers;
}

// Stash the per-request resolved CORS headers on the response so the
// many sendJson call sites stay one-arg and don't have to thread req
// through every helper. The top of createServer sets it once per req.
export function sendJson(res: ServerResponse & { __sugarmagicCors?: Record<string, string> }, statusCode: number, payload: unknown): void {
  res.writeHead(statusCode, {
    ..._baseHeaders,
    ...(res.__sugarmagicCors ?? {})
  });
  res.end(JSON.stringify(payload, null, 2));
}

