export async function handleSugarAgentGenerate(
  req: IncomingMessage,
  res: ServerResponse & { __sugarmagicCors?: Record<string, string> }
): Promise<void> {
  if (req.method !== "POST") {
    sendMethodNotAllowed(res, ["POST", "OPTIONS"]);
    return;
  }

  const body = await readJsonBody(req);
  const model =
    typeof body["model"] === "string" && body["model"].trim()
      ? body["model"].trim()
      : resolveEnv("SUGARMAGIC_SUGARAGENT_ANTHROPIC_MODEL", "claude-sonnet-4-5");
  const systemPrompt =
    typeof body["systemPrompt"] === "string" ? body["systemPrompt"].trim() : "";
  const userPrompt =
    typeof body["userPrompt"] === "string" ? body["userPrompt"].trim() : "";
  const maxTokens =
    typeof body["maxTokens"] === "number" && Number.isFinite(body["maxTokens"])
      ? Math.max(1, Math.floor(body["maxTokens"]))
      : 300;

  if (!systemPrompt || !userPrompt) {
    sendJson(res, 400, {
      ok: false,
      error: "InvalidRequest",
      message: "systemPrompt and userPrompt are required."
    });
    return;
  }

  const { payload, headers } = await requestJson(
    "https://api.anthropic.com/v1/messages",
    {
      method: "POST",
      headers: {
        "content-type": "application/json",
        "x-api-key": requireEnv("SUGARMAGIC_ANTHROPIC_API_KEY"),
        "anthropic-version": "2023-06-01"
      },
      body: JSON.stringify({
        model,
        max_tokens: maxTokens,
        system: systemPrompt,
        messages: [
          {
            role: "user",
            content: userPrompt
          }
        ]
      })
    },
    "Anthropic request"
  );

  const text = Array.isArray((payload as { content?: unknown[] })?.content)
    ? (payload as { content: Array<{ type: string; text?: string }> }).content
        .filter((block) => block?.type === "text" && typeof block.text === "string")
        .map((block) => block.text!.trim())
        .filter(Boolean)
        .join("\n\n")
    : "";

  if (!text) {
    throw new Error("Anthropic response did not include text content.");
  }

  sendJson(res, 200, {
    text,
    requestId: headers.get("request-id")
  });
}

export async function handleSugarAgentSearch(
  req: IncomingMessage,
  res: ServerResponse & { __sugarmagicCors?: Record<string, string> }
): Promise<void> {
  if (req.method !== "POST") {
    sendMethodNotAllowed(res, ["POST", "OPTIONS"]);
    return;
  }

  const body = await readJsonBody(req);
  const query = typeof body["query"] === "string" ? body["query"].trim() : "";
  const vectorStoreId =
    typeof body["vectorStoreId"] === "string" && body["vectorStoreId"].trim()
      ? body["vectorStoreId"].trim()
      : resolveEnv("SUGARMAGIC_SUGARAGENT_OPENAI_VECTOR_STORE_ID");
  const maxResults =
    typeof body["maxResults"] === "number" && Number.isFinite(body["maxResults"])
      ? Math.max(1, Math.min(8, Math.floor(body["maxResults"])))
      : 4;

  if (!query || !vectorStoreId) {
    sendJson(res, 400, {
      ok: false,
      error: "InvalidRequest",
      message: "query and vectorStoreId are required."
    });
    return;
  }

  const { payload, headers } = await requestJson(
    "https://api.openai.com/v1/vector_stores/" + vectorStoreId + "/search",
    {
      method: "POST",
      headers: {
        "content-type": "application/json",
        authorization: "Bearer " + requireEnv("SUGARMAGIC_OPENAI_API_KEY")
      },
      body: JSON.stringify({
        query,
        max_num_results: maxResults,
        filters:
          body["filters"] && typeof body["filters"] === "object" && !Array.isArray(body["filters"])
            ? body["filters"]
            : undefined
      })
    },
    "OpenAI vector search"
  );

  const results = Array.isArray((payload as { data?: unknown[] })?.data)
    ? (payload as { data: Array<Record<string, unknown>> }).data.map((result, index) => ({
        fileId:
          typeof result?.["file_id"] === "string" ? result["file_id"] : "vector-result-" + index,
        filename: typeof result?.["filename"] === "string" ? result["filename"] : "unknown",
        score: typeof result?.["score"] === "number" ? result["score"] : 0,
        attributes:
          result?.["attributes"] && typeof result["attributes"] === "object"
            ? result["attributes"]
            : {},
        text: Array.isArray(result?.["content"])
          ? (result["content"] as Array<{ type: string; text?: string }>)
              .filter((item) => item?.type === "text" && typeof item.text === "string")
              .map((item) => item.text!.trim())
              .filter(Boolean)
              .join("\n\n")
          : ""
      }))
    : [];

  sendJson(res, 200, {
    results,
    requestId: headers.get("x-request-id")
  });
}

export async function handleSugarAgentLoreStatus(
  req: IncomingMessage,
  res: ServerResponse & { __sugarmagicCors?: Record<string, string> }
): Promise<void> {
  if (req.method !== "GET") {
    sendMethodNotAllowed(res, ["GET", "OPTIONS"]);
    return;
  }

  const lore = readLorePages();
  const vectorStoreId = resolveEnv("SUGARMAGIC_SUGARAGENT_OPENAI_VECTOR_STORE_ID") || null;
  sendJson(res, 200, {
    ok: true,
    sourceKind: lore.source.sourceKind,
    sourceReady: lore.source.sourceReady,
    sourcePath: lore.source.sourcePath,
    vectorStoreId,
    pageCount: lore.pages.length,
    chunkCount: lore.chunks.length,
    warnings: lore.warnings,
    ingest: { ..._loreIngestState }
  });
}

export async function handleSugarAgentLorePages(
  req: IncomingMessage,
  res: ServerResponse & { __sugarmagicCors?: Record<string, string> }
): Promise<void> {
  if (req.method !== "GET") {
    sendMethodNotAllowed(res, ["GET", "OPTIONS"]);
    return;
  }

  const lore = readLorePages();
  sendJson(res, 200, {
    ok: true,
    pages: lore.pages.map((page) => ({
      pageId: page.pageId,
      title: page.title,
      relativePath: page.relativePath,
      sectionCount: page.sectionCount
    })),
    warnings: lore.warnings
  });
}

export async function handleSugarAgentLoreResolve(
  req: IncomingMessage,
  res: ServerResponse & { __sugarmagicCors?: Record<string, string> }
): Promise<void> {
  if (req.method !== "POST") {
    sendMethodNotAllowed(res, ["POST", "OPTIONS"]);
    return;
  }

  const body = await readJsonBody(req);
  const rawPageIds = Array.isArray(body?.["pageIds"]) ? body["pageIds"] as unknown[] : [];
  const pageIds = [...new Set(
    rawPageIds
      .filter((value) => typeof value === "string")
      .map((value) => (value as string).trim())
      .filter(Boolean)
  )].sort((left, right) => left.localeCompare(right));

  if (pageIds.length === 0) {
    sendJson(res, 400, {
      ok: false,
      error: "InvalidRequest",
      message: "pageIds must contain at least one non-empty lore page id."
    });
    return;
  }

  const lore = readLorePages();
  const pagesById = new Map(
    lore.pages.map((page) => [page.pageId, page])
  );
  const resolvedPages: LorePage[] = [];
  const missingPageIds: string[] = [];

  for (const pageId of pageIds) {
    const page = pagesById.get(pageId);
    if (!page) {
      missingPageIds.push(pageId);
      continue;
    }
    // Plan 072.2: `## Secrets` must not leave the gateway. Strip it from BOTH
    // `sections` and `body` (sugarlang's consumer feeds each into the scene
    // lexicon). Pages without a secret section pass through byte-identical --
    // only recompute `body` when a secret is actually being removed, so the
    // raw markdown is preserved for the common case.
    const hasSecret = page.sections.some(isSecretSection);
    if (!hasSecret) {
      resolvedPages.push({
        pageId: page.pageId,
        title: page.title,
        relativePath: page.relativePath,
        sectionCount: page.sectionCount,
        body: page.body,
        sections: page.sections
      });
      continue;
    }
    const visibleSections = page.sections.filter(
      (section) => !isSecretSection(section)
    );
    resolvedPages.push({
      pageId: page.pageId,
      title: page.title,
      relativePath: page.relativePath,
      sectionCount: visibleSections.length,
      body: composeLoreBody(visibleSections),
      sections: visibleSections
    });
  }

  sendJson(res, 200, {
    ok: true,
    pages: resolvedPages,
    missingPageIds,
    warnings: lore.warnings
  });
}

export async function handleSugarAgentLoreIngest(
  req: IncomingMessage,
  res: ServerResponse & { __sugarmagicCors?: Record<string, string> }
): Promise<void> {
  if (req.method !== "POST") {
    sendMethodNotAllowed(res, ["POST", "OPTIONS"]);
    return;
  }

  const body = await readJsonBody(req);
  const mode = "overwrite";
  const vectorStoreId =
    typeof body["vectorStoreId"] === "string" && body["vectorStoreId"].trim()
      ? body["vectorStoreId"].trim()
      : resolveEnv("SUGARMAGIC_SUGARAGENT_OPENAI_VECTOR_STORE_ID");

  if (!vectorStoreId) {
    sendJson(res, 400, {
      ok: false,
      error: "InvalidRequest",
      message: "vectorStoreId is required."
    });
    return;
  }

  const lore = readLorePages();
  if (!lore.source.sourceReady) {
    sendJson(res, 400, {
      ok: false,
      error: "LoreSourceUnavailable",
      message: lore.warnings[0] ?? "Lore source is not available."
    });
    return;
  }

  if (lore.chunks.length === 0) {
    sendJson(res, 400, {
      ok: false,
      error: "LoreSourceEmpty",
      message: "No lore pages with canonical frontmatter ids were found in the configured lore source.",
      warnings: lore.warnings
    });
    return;
  }

  updateLoreIngestState({
    active: true,
    phase: "parsed",
    pageCount: lore.pages.length,
    chunkCount: lore.chunks.length,
    uploadedCount: 0,
    currentChunkId: null,
    message: "Parsed " + lore.pages.length + " pages into " + lore.chunks.length + " chunks.",
    warnings: lore.warnings,
    startedAt: new Date().toISOString(),
    completedAt: null
  });

  try {
    if (mode === "overwrite") {
      updateLoreIngestState({
        phase: "clearing-store",
        message: "Clearing existing vector store contents before overwrite."
      });
      const existingFiles = await listVectorStoreFiles(vectorStoreId);
      for (const item of existingFiles) {
        if (typeof item?.["id"] === "string") {
          await deleteVectorStoreFile(vectorStoreId, item["id"] as string);
        }
      }
    }

    let uploadedCount = 0;
    for (const chunk of lore.chunks) {
      await uploadChunkToVectorStore(vectorStoreId, chunk, (progress) => {
        updateLoreIngestState({
          phase: progress.phase,
          currentChunkId: progress.currentChunkId ?? null,
          message: progress.message,
          uploadedCount
        });
      });
      uploadedCount += 1;
      updateLoreIngestState({
        phase: "uploading",
        currentChunkId: chunk.chunkId,
        uploadedCount,
        message: "Uploaded " + uploadedCount + " / " + lore.chunks.length + " chunks."
      });
    }

    updateLoreIngestState({
      active: false,
      phase: "completed",
      currentChunkId: null,
      uploadedCount,
      message: "Completed lore ingest.",
      completedAt: new Date().toISOString()
    });

    sendJson(res, 200, {
      ok: true,
      mode,
      vectorStoreId,
      pageCount: lore.pages.length,
      chunkCount: lore.chunks.length,
      uploadedCount,
      warnings: lore.warnings
    });
  } catch (error) {
    updateLoreIngestState({
      active: false,
      phase: "failed",
      message: error instanceof Error ? error.message : String(error),
      completedAt: new Date().toISOString()
    });
    throw error;
  }
}

// ---------------------------------------------------------------------------
// Server
// ---------------------------------------------------------------------------

type GatewayRequest = IncomingMessage & { __sugarmagicCors?: Record<string, string>; user?: { userId: string; email: string | null } };
type GatewayResponse = ServerResponse & { __sugarmagicCors?: Record<string, string> };

export const server = createServer(async (req: GatewayRequest, res: GatewayResponse) => {
  // Story 46.9 — resolve CORS headers once per request, stash on the
  // response, then sendJson / sendMethodNotAllowed read them off the
  // response so call sites don't have to thread req.
  res.__sugarmagicCors = resolveCorsHeaders(req);

  if (req.method === "OPTIONS") {
    // CORS preflight. Echo the request's
    // access-control-request-headers verbatim when present so we don't
    // have to enumerate them; fall back to a safe default.
    const requestedHeaders = req.headers["access-control-request-headers"];
    res.writeHead(204, {
      ..._baseHeaders,
      ...res.__sugarmagicCors,
      "access-control-allow-methods": "GET,POST,PUT,PATCH,DELETE,OPTIONS",
      "access-control-allow-headers":
        typeof requestedHeaders === "string" && requestedHeaders.length > 0
          ? requestedHeaders
          : "content-type, authorization",
      "access-control-max-age": "86400"
    });
    res.end();
    return;
  }

  const path = normalizePath(req.url);
  logInfo("gateway:request", {
    method: req.method ?? "GET",
    path
  });
  // /health (not /healthz): Cloud Run's frontend reserves /healthz
  // specifically — it gets intercepted before reaching the container,
  // returning Google's generic 404 page with no x-cloud-trace-context
  // header. Discovered the hard way during 45.5.7 verification.
  if (path === "/" || path === "/health") {
    sendJson(res, 200, {
      ok: true,
      target: _targetId,
      serviceUnitId: _serviceUnitId,
      routes: _routes
    });
    return;
  }

  // Story 45.5.8 / Story 47.9 — auth gate. Assembled based on the effective
  // gatewayAuthMode at plan time:
  //   - "none"          -> no gate
  //   - "bearer"        -> shared-token check (45.5.8)
  //   - "supabase-jwt"  -> Supabase HS256/ES256 verification (47.9)
  // /health stays public above; this gate runs on EVERY other path before
  // the route dispatcher.
  /*! __GATEWAY_AUTH_GATE__ */

  const match = findManagedRoute(path);
  if (!match) {
    logInfo("gateway:route-not-managed", {
      path,
      knownRoutes: _routes.map((route) => route.path)
    });
    sendJson(res, 404, {
      ok: false,
      error: "RouteNotManaged",
      message: "SugarDeploy generated this gateway scaffold, but the requested route is not declared for this service unit.",
      path,
      knownRoutes: _routes.map((route) => route.path)
    });
    return;
  }

  try {
    if (match.routeId === "sugaragent-generate" && path === match.path) {
      logInfo("gateway:dispatch", {
        routeId: match.routeId,
        path
      });
      await handleSugarAgentGenerate(req, res);
      return;
    }

    if (match.routeId === "sugaragent-retrieve" && path === match.path + "/search") {
      logInfo("gateway:dispatch", {
        routeId: match.routeId,
        path
      });
      await handleSugarAgentSearch(req, res);
      return;
    }

    if (match.routeId === "sugaragent-lore" && path === match.path + "/status") {
      logInfo("gateway:dispatch", {
        routeId: match.routeId,
        path
      });
      await handleSugarAgentLoreStatus(req, res);
      return;
    }

    if (match.routeId === "sugaragent-lore" && path === match.path + "/pages") {
      logInfo("gateway:dispatch", {
        routeId: match.routeId,
        path
      });
      await handleSugarAgentLorePages(req, res);
      return;
    }

    if (match.routeId === "sugaragent-lore" && path === match.path + "/resolve") {
      logInfo("gateway:dispatch", {
        routeId: match.routeId,
        path
      });
      await handleSugarAgentLoreResolve(req, res);
      return;
    }

    if (match.routeId === "sugaragent-lore" && path === match.path + "/ingest") {
      logInfo("gateway:dispatch", {
        routeId: match.routeId,
        path
      });
      await handleSugarAgentLoreIngest(req, res);
      return;
    }

    logInfo("gateway:route-unimplemented", {
      routeId: match.routeId,
      path
    });
    sendJson(res, 501, {
      ok: false,
      error: "ProxyHandlerNotImplemented",
      target: _targetId,
      serviceUnitId: _serviceUnitId,
      route: match,
      request: {
        method: req.method,
        path
      },
      message:
        "SugarDeploy generated the backend gateway scaffold for this route, but no concrete handler is registered for this path yet."
    });
  } catch (error) {
    logError("gateway:handler-failure", error, {
      routeId: match.routeId,
      path
    });
    sendJson(res, 500, {
      ok: false,
      error: "GatewayProxyFailure",
      target: _targetId,
      serviceUnitId: _serviceUnitId,
      route: match,
      path,
      message: error instanceof Error ? error.message : String(error)
    });
  }
});

// ---------------------------------------------------------------------------
// Entry point (only when run as a script, not when imported for testing)
// ---------------------------------------------------------------------------

const __gatewayFilename = fileURLToPath(import.meta.url);
if (process.argv[1] === __gatewayFilename) {
  const __dir = dirname(__gatewayFilename);
  const manifest = JSON.parse(readFileSync(join(__dir, "routes.json"), "utf8")) as RouteManifest;
  initGateway(manifest);
  const port = Number(process.env["PORT"] || manifest.containerPort || 8080);
  server.listen(port, () => {
    console.log("[sugardeploy] gateway " + manifest.serviceUnitId + " listening on port " + port);
  });
}
